import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, readFileSync, rmSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { editHistoryTracker, getEditHistoryPath } from '../../../posttool/write/edit-history-tracker.js';
import { NOOP_CTX } from '../../../lib/context.js';

describe('edit-history-tracker', () => {
  let tmp: string;

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'edit-tracker-'));
  });
  afterEach(() => {
    rmSync(tmp, { recursive: true, force: true });
  });

  test('getEditHistoryPath returns .claude/state/edit-history.jsonl', () => {
    expect(getEditHistoryPath(tmp)).toBe(join(tmp, '.claude', 'state', 'edit-history.jsonl'));
  });

  test('silent for non-tracked tools', () => {
    const input = { tool_name: 'Bash', session_id: 's', tool_input: { command: 'ls' } } as never;
    const r = editHistoryTracker(input, { ...NOOP_CTX, projectDir: tmp });
    expect(r.hookSpecificOutput).toBeUndefined();
    expect(existsSync(getEditHistoryPath(tmp))).toBe(false);
  });

  test('silent when file_path is missing', () => {
    const input = { tool_name: 'Write', session_id: 's', tool_input: {} } as never;
    editHistoryTracker(input, { ...NOOP_CTX, projectDir: tmp });
    expect(existsSync(getEditHistoryPath(tmp))).toBe(false);
  });

  test('appends one JSONL line per Write', () => {
    const input = { tool_name: 'Write', session_id: 's', tool_input: { file_path: '/src/a.ts' } } as never;
    editHistoryTracker(input, { ...NOOP_CTX, projectDir: tmp });
    editHistoryTracker(input, { ...NOOP_CTX, projectDir: tmp });
    const lines = readFileSync(getEditHistoryPath(tmp), 'utf8').trim().split('\n');
    expect(lines.length).toBe(2);
    const parsed = JSON.parse(lines[0]);
    expect(parsed.f).toBe('/src/a.ts');
    expect(parsed.tool).toBe('Write');
    expect(typeof parsed.t).toBe('number');
  });

  test('tracks Edit and MultiEdit equally', () => {
    for (const tool_name of ['Edit', 'MultiEdit']) {
      const input = { tool_name, session_id: 's', tool_input: { file_path: '/x.ts' } } as never;
      editHistoryTracker(input, { ...NOOP_CTX, projectDir: tmp });
    }
    const lines = readFileSync(getEditHistoryPath(tmp), 'utf8').trim().split('\n');
    expect(lines.map((l: string) => JSON.parse(l).tool)).toEqual(['Edit', 'MultiEdit']);
  });
});
